import { Component } from '@angular/core';
import { FormControl, FormGroup, FormsModule, ReactiveFormsModule } from '@angular/forms';

interface Shoes {
  value: string;
  name: string;
}

@Component({
  selector: 'app-instruction',
  templateUrl: './instruction.component.html',
  styleUrls: ['./instruction.component.css']
})
export class InstructionComponent {
  form: FormGroup;
  shoes: Shoes[] = [
    { value: 'boots', name: 'Boots' },
    { value: 'clogs', name: 'Clogs' },
    { value: 'loafers', name: 'Loafers' },
    { value: 'moccasins', name: 'Moccasins' },
    { value: 'sneakers', name: 'Sneakers' },
  ];
  shoesControl = new FormControl();

  constructor() {
    this.form = new FormGroup({
      clothes: this.shoesControl,
    });
  }
}
<form [formGroup]="form">
  <mat-selection-list #shoesList [formControl]="shoesControl" name="shoes" [multiple]="false" *ngFor="let shoe of shoes">
    <mat-list-option [value]="shoe.value">{{shoe.name}}</mat-list-option>
  </mat-selection-list>  
</form>
